#include <bits/stdc++.h>
using namespace std;
__int128 C[102][102];
void write(__int128 x) {
    if(x<0)
        putchar('-'),x=-x;
    if(x>9)
        write(x/10);
    putchar(x%10+'0');
}
int main(){
    for(int i=0;i<=100;i++)
        for(int j=0;j<=i;j++)
            C[i][j]=(j==0 || j==i?1:C[i-1][j]+C[i-1][j-1]);
    int n,a,b;
    scanf("%d%d%d",&n,&a,&b);
    write(C[n+a][n]*C[n+b][n]);
    return 0;
}
